// Build Prometheus text format response from global counter state.
const counters = global.get('metrics') || {};
const tickCount = (flow.get('kafka_tick_count') || 0)
    + (flow.get('mqtt_tick_count') || 0);

function fmt(name, help, type, samples) {
    let out = '# HELP ' + name + ' ' + help + '\n';
    out += '# TYPE ' + name + ' ' + type + '\n';
    for (const [labels, value] of samples) {
        const labelStr = Object.entries(labels).map(([k, v]) => k + '="' + v + '"').join(',');
        out += name + (labelStr ? '{' + labelStr + '}' : '') + ' ' + value + '\n';
    }
    return out;
}

let body = '';
body += fmt('facis_sim_ticks_total', 'Total simulation ticks emitted', 'counter', [
    [{ runtime: 'orce-native' }, tickCount]
]);

const kafkaTotals = counters.kafka_messages_sent_total || {};
body += fmt('facis_kafka_messages_sent_total', 'Total Kafka messages sent', 'counter',
    Object.entries(kafkaTotals).map(([topic, v]) => [{ topic }, v]));

const mqttTotals = counters.mqtt_messages_sent_total || {};
body += fmt('facis_mqtt_messages_sent_total', 'Total MQTT messages sent', 'counter',
    Object.entries(mqttTotals).map(([topic, v]) => [{ topic }, v]));

const modbusTotals = counters.modbus_requests_total || {};
body += fmt('facis_modbus_requests_total', 'Total Modbus requests served', 'counter',
    Object.entries(modbusTotals).map(([fc, v]) => [{ register_type: fc }, v]));

msg.payload = body;
msg.headers = { 'Content-Type': 'text/plain; version=0.0.4' };
msg.statusCode = 200;
return msg;

// Structured JSON log + DLQ payload for any uncaught error.
const ts = new Date().toISOString();
const entry = {
    timestamp: ts,
    level: 'error',
    service: 'facis-simulation-orce',
    source_tab: msg.error && msg.error.source ? msg.error.source.id : 'unknown',
    source_name: msg.error && msg.error.source ? msg.error.source.name : null,
    message: msg.error ? (msg.error.message || String(msg.error)) : 'unknown error',
    payload_excerpt: typeof msg.payload === 'string' ? msg.payload.slice(0, 256) : null
};
node.error(JSON.stringify(entry));
msg.topic = 'sim.dead_letter';
msg.payload = JSON.stringify(entry);
return msg;

const m = global.get('metrics') || {};
const family = msg.payload && msg.payload.family;
const label = msg.payload && msg.payload.label;
const inc = (msg.payload && typeof msg.payload.value === 'number') ? msg.payload.value : 1;
if (!family || !label) {
    node.warn('metric.inc: missing family or label');
    return null;
}
if (!m[family]) m[family] = {};
m[family][label] = (m[family][label] || 0) + inc;
global.set('metrics', m);
return null;
